mapper.select:
SELECT r.id, r.account_id, a.nick AS nickname, a.profile_img_url AS profile_image_url,
       r.period_type, r.period_bucket, r.difficulty,
       r.elapsed_ms, r.target_word, r.start_doc, r.path_length, r.created_at
FROM ranking_records r
JOIN accounts a ON r.account_id = a.account_id
WHERE r.period_type  = #{periodType}
  AND r.difficulty   = #{difficulty}
  AND r.period_bucket = #{bucket}
ORDER BY r.elapsed_ms ASC, r.created_at ASC
LIMIT 100

SELECT r.id, r.account_id, a.nick AS nickname, a.profile_img_url AS profile_image_url,
       r.period_type, r.period_bucket, r.difficulty,
       r.elapsed_ms, r.target_word, r.start_doc, r.path_length, r.created_at
FROM ranking_records r
JOIN accounts a ON r.account_id = a.account_id
WHERE r.period_type   = #{periodType}
  AND r.difficulty    = #{difficulty}
  AND r.period_bucket = #{bucket}
  AND r.account_id    = #{accountId}
LIMIT 1

SELECT COUNT(*) FROM ranking_records
WHERE period_type   = #{periodType}
  AND difficulty    = #{difficulty}
  AND period_bucket = #{bucket}

SELECT elapsed_ms FROM ranking_records
WHERE period_type   = #{periodType}
  AND difficulty    = #{difficulty}
  AND period_bucket = #{bucket}
ORDER BY elapsed_ms ASC, created_at ASC
LIMIT 1 OFFSET 99

mapper.update:
UPDATE ranking_records
SET elapsed_ms   = #{elapsedMs},
    target_word  = #{targetWord},
    start_doc    = #{startDoc},
    path_length  = #{pathLength},
    created_at   = CURRENT_TIMESTAMP
WHERE period_type   = #{periodType}
  AND period_bucket = #{periodBucket}
  AND difficulty    = #{difficulty}
  AND account_id    = #{accountId}

mapper.delete:
DELETE FROM ranking_records
WHERE id IN (
    SELECT id FROM ranking_records
    WHERE period_type   = #{periodType}
      AND difficulty    = #{difficulty}
      AND period_bucket = #{bucket}
    ORDER BY elapsed_ms ASC, created_at ASC
    OFFSET 100
)
